#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

// Simple open‑addressing hash table for 64‑bit keys
typedef struct {
    uint64_t key;
    uint64_t cnt;
    int used;
} Entry;

typedef struct {
    Entry *table;
    size_t size; // power of two
    size_t mask;
} HashMap;

static uint64_t mix64(uint64_t x) {
    x ^= x >> 33;
    x *= 0xff51afd7ed558ccdULL;
    x ^= x >> 33;
    x *= 0xc4ceb9fe1a85ec53ULL;
    x ^= x >> 33;
    return x;
}

static HashMap *hm_create(size_t capacity) {
    HashMap *hm = (HashMap *)malloc(sizeof(HashMap));
    size_t sz = 1;
    while (sz < capacity) sz <<= 1;
    hm->size = sz;
    hm->mask = sz - 1;
    hm->table = (Entry *)calloc(sz, sizeof(Entry));
    return hm;
}

static void hm_inc(HashMap *hm, uint64_t key) {
    size_t idx = mix64(key) & hm->mask;
    while (hm->table[idx].used) {
        if (hm->table[idx].key == key) {
            hm->table[idx].cnt++;
            return;
        }
        idx = (idx + 1) & hm->mask;
    }
    hm->table[idx].used = 1;
    hm->table[idx].key = key;
    hm->table[idx].cnt = 1;
}

static uint64_t hm_get(HashMap *hm, uint64_t key) {
    size_t idx = mix64(key) & hm->mask;
    while (hm->table[idx].used) {
        if (hm->table[idx].key == key) return hm->table[idx].cnt;
        idx = (idx + 1) & hm->mask;
    }
    return 0ULL;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        unsigned long long k;
        scanf("%d %llu", &N, &k);
        unsigned long long *a = (unsigned long long *)malloc(N * sizeof(unsigned long long));
        for (int i = 0; i < N; ++i) scanf("%llu", &a[i]);
        HashMap *hm = hm_create(N * 2 + 1);
        unsigned long long ans = 0ULL;
        for (int i = N - 1; i >= 0; --i) {
            unsigned long long Ai = a[i];
            if (k >= Ai) {
                unsigned long long target = k - Ai;
                unsigned long long need = Ai ^ target;
                ans += hm_get(hm, need);
            }
            hm_inc(hm, Ai);
        }
        printf("%llu\n", ans);
        free(a);
        free(hm->table);
        free(hm);
    }
    return 0;
}

